import React, { useState } from 'react';
import './App.css';

export default function App() {
  const [tasks, setTasks] = useState([]);
  const [input, setInput] = useState('');

  const add = () => input.trim() && (setTasks([...tasks, { id: Date.now(), text: input, done: false }]), setInput(''));

  return (
    <div className="todo-container">
      <h2 style={{color: '#4A90E2'}}>To-Do List</h2>
      <div className="todo-input-wrapper">
        <input value={input} onChange={(e) => setInput(e.target.value)} placeholder="Add a new task..." className="todo-input" />
        <button onClick={add} className="add-task-button">Add Task</button>
      </div>
      <ul className="todo-list">
        {tasks.map(t => (
          <li key={t.id} className={`todo-item ${t.done ? 'done' : ''}`}>
            <span onClick={() => setTasks(tasks.map(x => x.id === t.id ? {...x, done: !x.done} : x))}>{t.text}</span>
            <button onClick={() => setTasks(tasks.filter(x => x.id !== t.id))}>×</button>
          </li>
        ))}
      </ul>
    </div>
  );
}
